const domain = $json.searchKeyword || "general";

const jobs = items.map(item => {

  // 🔹 Extract + clean description FIRST
  const fullDescription = item.json.jobDescription 
                       || item.json.description_text 
                       || item.json.description 
                       || '';

  const cleanDescription = fullDescription
    .replace(/\s+/g, ' ')
    .trim();

  return {
    title: item.json.jobTitle || item.json.title || 'Unknown',

    company: item.json.companyName 
             || item.json.company?.companyName 
             || item.json.company 
             || 'Unknown',

    location: item.json.location?.city 
              || item.json.location?.state 
              || item.json.location?.country 
              || (typeof item.json.location === 'string' ? item.json.location : null)
              || 'India',

    // 🔥 trimmed but useful
    description: cleanDescription.slice(0, 2500),

    link: item.json.applyUrl 
          || item.json.jobUrl 
          || item.json.link 
          || `no-link-${Date.now()}`,

    postedAt: item.json.postedAt 
              || item.json.datePublished 
              || new Date().toISOString(),

    rawData: {
      domainScraped: domain
    }
  };
});

const validJobs = jobs.filter(j => 
  j.title !== 'Unknown' && 
  j.description && 
  j.description.length > 20
);

return [{
  json: {
    domain,
    jobs: validJobs,
    totalScraped: items.length,
    totalValid: validJobs.length
  }
}];

const users = $json.users || [];
return users.map(u => {
  return {
    json: { userId: u.id, email: u.email }
  };
});

// ⑤ Pick Top 5 DB Matches
// Backend now returns pre-filtered, re-ranked top 5 matches.
// This node validates and formats them for resume generation.
const response = $json || {};
const matches = Array.isArray(response.matches) ? response.matches : [];
const userId = $('③ Loop Per User').first().json.userId;
const isFiltered = response.filtered === true;

// Guard: if backend returned zero matches after post-filtering, skip resume gen
if (matches.length === 0) {
  console.log(`[n8n] No matches for user ${userId} after ${isFiltered ? 'post-filtering' : 'search'}. Skipping resume generation.`);
  return [{ json: { userId, message: 'No matches survived post-filtering', skipped: true } }];
}

// Take up to 5 (backend already limits, but defensive)
const topMatches = matches.slice(0, 5);

console.log(`[n8n] User ${userId}: ${topMatches.length} jobs passed to resume generation`);

return topMatches.map(m => ({
  json: {
    userId,
    jobId: m.jobId,
    matchScore: m.score
  }
}));

const userId = $('③ Loop Per User').first().json.userId;
const matchMethod = $('④ Semantic Match Index Search').first().json.method || 'unknown';
const matchCount = ($('④ Semantic Match Index Search').first().json.matches || []).length;

let resumeSuccessCount = 0;
let resumeFailCount = 0;
for (const item of items) {
  if (item.json.success === true) {
    resumeSuccessCount++;
  } else {
    resumeFailCount++;
  }
}

return [{
  json: {
    userId,
    matchCount,
    matchMethod,
    resumeSuccessCount,
    resumeFailCount,
    done: true
  }
}];
